class Solution {
    public long repairCars(int[] ranks, int cars) {
        Arrays.sort(ranks);
        long time = 0;
        for (int i = 0; i < ranks.length && cars > 0; i++) {
            int carsRepaired = Math.min(cars, ranks[i]);
            time += (long) (ranks[i] * carsRepaired * carsRepaired);
            cars -= carsRepaired;
        }
        return time;
    }
}
```
